import{c as t,Q as o,j as s,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Stop Obsessing Over Prompts. Your Real Problem Is Probably CLAUDE.md","description":"","frontmatter":{"title":"Stop Obsessing Over Prompts. Your Real Problem Is Probably CLAUDE.md","author":"@NainsiDwiv50980 (Nainsi Dwivedi)","date":"2026-05-18T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-18-@NainsiDwiv50980-909056.md","filePath":"research/tweets/2026-05-18-@NainsiDwiv50980-909056.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-05-18-@NainsiDwiv50980-909056.md"};function a(n,e,p,l,h,u){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="stop-obsessing-over-prompts-your-real-problem-is-probably-claude-md" tabindex="-1">Stop Obsessing Over Prompts. Your Real Problem Is Probably CLAUDE.md <a class="header-anchor" href="#stop-obsessing-over-prompts-your-real-problem-is-probably-claude-md" aria-label="Permalink to &quot;Stop Obsessing Over Prompts. Your Real Problem Is Probably CLAUDE.md&quot;">​</a></h1><ul><li><strong>作者</strong>：@NainsiDwiv50980 (Nainsi Dwivedi)</li><li><strong>原文</strong>：<a href="https://x.com/NainsiDwiv50980/status/2056406042653909056" target="_blank" rel="noreferrer">https://x.com/NainsiDwiv50980/status/2056406042653909056</a></li><li><strong>發布時間</strong>：2026-05-18</li><li><strong>統計</strong>：👍 117 · 🔁 35 · 🔖 86 · 👁 3,496</li><li><strong>評分</strong>：6.65/10 · <strong>整合決策</strong>：Rule</li></ul><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>CLAUDE.md 是「錯誤防範系統」而非指令清單；context engineering 比 prompt engineering 更有競爭優勢。</p><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li>Claude 每次 session 都是「context-blind」，無法自動了解專案架構、慣例與決策歷史</li><li>CLAUDE.md 真正目的是<strong>消除決策歧義</strong>，不是給更多指令</li><li>三大常見失敗模式：檔案過長、指令太通用（&quot;Write clean code&quot;）、無層次結構</li><li>5 大必要區塊：Commands、Architecture Map、Hard Rules、Workflow Behavior、Out-of-Scope Boundaries</li><li>優秀的 CLAUDE.md 隨時間演化為 institutional memory，持續複利積累</li></ol><h2 id="關鍵數據-框架" tabindex="-1">關鍵數據 / 框架 <a class="header-anchor" href="#關鍵數據-框架" aria-label="Permalink to &quot;關鍵數據 / 框架&quot;">​</a></h2><ul><li><strong>Hard Rules 自我測試</strong>：「若移除此規則，Claude 會犯代價高昂的錯誤嗎？是 → 保留；否 → 刪除」</li><li><strong>負面規則同樣重要</strong>：告訴 Claude「不要做什麼」比「要做什麼」更有效</li><li><strong>層次分離</strong>：global rules → project rules → personal workflow preferences</li></ul><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>缺乏量化驗證</strong>：全為 anecdotal 觀察，無 before/after 比較或可重現數據</li><li><strong>5 大區塊框架未解釋選擇理由</strong>：為何是這 5 個？缺乏結構化推導</li><li><strong>進階用戶深度不足</strong>：對已在使用 CLAUDE.md 的用戶，缺少具體邊界案例或反直覺洞察</li></ol><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Most developers think they&#39;re getting bad results from Claude because: • the prompts aren&#39;t detailed enough • the model isn&#39;t smart enough • AI still &quot;isn&#39;t there yet&quot;</p><p>But after watching how different developers use Claude Code, I&#39;ve realized something:</p><p>The biggest difference between average outputs and insanely good outputs usually has nothing to do with prompting.</p><p>It comes from context.</p><p>More specifically:</p><p>CLAUDE.md.</p><p>And honestly?</p><p>Most people are using it completely wrong.</p><p>They treat it like a random notes file.</p><p>Or worse… they ignore it entirely.</p><p>Meanwhile, advanced users treat CLAUDE.md like the operating system for their entire AI workflow.</p><p>That&#39;s why one developer feels like they&#39;re fighting the model constantly…</p><p>while another feels like they hired a senior engineer who already understands the codebase.</p><p>Same model.</p><p>Completely different setup.</p><p><strong>The Hidden Reason Claude Feels &quot;Inconsistent&quot;</strong></p><p>A lot of developers don&#39;t realize this, but Claude starts every session context-blind.</p><p>It has no idea: • how your project is structured • what patterns you follow • what architecture decisions exist • which mistakes matter most • what your workflow expectations are</p><p>So unless you define those things clearly…</p><p>Claude improvises.</p><p>And improvisation is exactly where inconsistent outputs begin.</p><p>That&#39;s why one session feels brilliant…</p><p>and the next feels frustrating.</p><p>Not because the model suddenly got worse.</p><p>Because the environment changed.</p><p><strong>The Real Purpose of CLAUDE.md</strong></p><p>Most people think CLAUDE.md exists to &quot;give instructions.&quot;</p><p>That&#39;s surface level.</p><p>The real purpose is much deeper:</p><p>It reduces decision ambiguity.</p><p>That&#39;s the entire game.</p><p>Good AI workflows are not built by endlessly adding more prompts.</p><p>They&#39;re built by removing uncertainty.</p><p>The best CLAUDE.md files don&#39;t try to control everything.</p><p>They simply prevent the most expensive mistakes from happening repeatedly.</p><p>That&#39;s a huge mindset shift.</p><p>CLAUDE.md is not a wishlist.</p><p>It&#39;s a mistake prevention system.</p><p>And once you understand that…</p><p>your entire workflow changes.</p><p><strong>Why Most CLAUDE.md Files Quietly Fail</strong></p><p>This is where almost everyone gets it wrong.</p><p>The first mistake: they make the file way too long.</p><p>People assume: more instructions = better outputs</p><p>Usually the opposite happens.</p><p>Every extra line competes for attention.</p><p>The longer your file becomes: • the weaker instruction adherence gets • the more context quality drops • the more important rules get diluted</p><p>Most high-performing setups are surprisingly minimal.</p><p>Because strong systems prioritize clarity over volume.</p><p>The second mistake: generic instructions.</p><p>Things like: • &quot;Write clean code&quot; • &quot;Be a senior engineer&quot; • &quot;Think step by step&quot;</p><p>These sound useful…</p><p>but they barely change behavior.</p><p>Claude already understands these concepts.</p><p>What actually matters are project-specific constraints.</p><p>The highest-value instructions are usually things like: • never modify deployment configs • always run type checks • use existing utilities only • avoid touching unrelated files • ask before architecture changes</p><p>Those instructions prevent real mistakes.</p><p>That&#39;s the difference.</p><p>The third mistake: no structure.</p><p>Most developers dump everything into one giant file: • workflow preferences • stack details • architecture notes • personal opinions • random reminders</p><p>All mixed together.</p><p>That creates noise.</p><p>Advanced users separate context intentionally: • global rules • project rules • personal workflow preferences</p><p>Cleaner hierarchy = cleaner outputs.</p><p><strong>The 5 Parts Every High-Quality CLAUDE.md Should Have</strong></p><p>After analyzing a lot of strong Claude workflows, almost every good setup includes these five areas.</p><ol><li>Commands</li></ol><p>Claude performs dramatically better when it understands how your project actually runs.</p><p>Without commands, it guesses.</p><p>And guessing creates unnecessary back-and-forth.</p><p>Simple things matter: • how to run dev • how to test • how to lint • how to type-check</p><p>This alone removes friction from almost every workflow.</p><ol start="2"><li>Architecture Map</li></ol><p>Claude doesn&#39;t magically understand your codebase structure.</p><p>You need to define the basics: • where business logic lives • where API routes exist • where UI components belong • where state management happens</p><p>Not every detail.</p><p>Just enough to stop bad placement decisions.</p><ol start="3"><li>Hard Rules</li></ol><p>This is probably the highest ROI section in the entire file.</p><p>Every rule should answer one question:</p><p>&quot;If I remove this, will Claude make expensive mistakes?&quot;</p><p>If yes: keep it.</p><p>If no: delete it.</p><p>The strongest rules are: • specific • enforceable • project-relevant</p><p>And honestly?</p><p>Negative rules matter just as much as positive ones.</p><p>Telling Claude what NOT to do is incredibly powerful.</p><ol start="4"><li>Workflow Behavior</li></ol><p>This controls how Claude approaches tasks.</p><p>Not just the final output.</p><p>Things like: • ask before major changes • make minimal edits only • explain tradeoffs first • separate commits logically • validate changes after edits</p><p>These dramatically improve collaboration quality.</p><p>The difference becomes obvious fast.</p><ol start="5"><li>Out-of-Scope Boundaries</li></ol><p>This section is massively underrated.</p><p>One of the best ways to improve AI consistency is clearly defining forbidden areas.</p><p>For example: • do not modify deployment configs • do not touch manually maintained files • avoid dependency changes • never alter production infrastructure automatically</p><p>Boundaries create stability.</p><p>And stability compounds.</p><p><strong>The Most Powerful Insight About CLAUDE.md</strong></p><p>This is the part most people miss entirely:</p><p>A great CLAUDE.md improves over time.</p><p>Every time Claude makes a mistake… you refine the system.</p><p>Over months, the file becomes: • institutional memory • workflow documentation • architecture guidance • error prevention • operational context</p><p>That&#39;s when Claude starts feeling dramatically smarter.</p><p>Not because the model changed.</p><p>Because your system evolved.</p><p>That&#39;s the real edge.</p><p>Most developers are still trying to &quot;prompt better.&quot;</p><p>Meanwhile advanced users are: • engineering context • refining workflows • reducing ambiguity • building reusable systems • designing operational environments</p><p>That&#39;s why their outputs feel so much more consistent.</p><p><strong>The Future Belongs to Developers Who Understand Context</strong></p><p>The biggest misconception in AI right now is thinking the competitive advantage comes from prompting.</p><p>It doesn&#39;t.</p><p>The real advantage comes from: • workflow design • context management • orchestration systems • memory architecture • operational consistency</p><p>Prompting is temporary.</p><p>Systems compound.</p><p>And honestly?</p><p>Most people are still extremely early to this shift.</p>',132)])])}const m=t(i,[["render",a]]);export{c as __pageData,m as default};
